    getEventsForState(stateId) {
        switch (stateId) {
            case 'not_initialized': return new Set(['C0FI']);
            case 'parked': return new Set(['C0FI', 'C0PG', 'C0FY']);
            case 'ready': return new Set(['C0FI', 'C0PG', 'C0GX', 'C0GY', 'C0GZ', 'C0PN', 'C0PT', 'C0RG', 'C0QP', 'C0QG', 'C0PC']);
            case 'empty': return new Set(['C0PP', 'C0GF', 'C0PO', 'C0PR', 'C0PM', 'C0PB', 'C0FI', 'C0PG', 'C0GX', 'C0GY', 'C0GZ', 'C0PN', 'C0PT', 'C0RG', 'C0QP', 'C0QG', 'C0PC']);
            case 'gripped': return new Set(['C0PR', 'C0PM', 'C0PB', 'C0PI', 'C0PP', 'C0FI', 'C0PG', 'C0GX', 'C0GY', 'C0GZ', 'C0PN', 'C0PT', 'C0RG', 'C0QP', 'C0QG', 'C0PC']);
            case 'error_iswap': return new Set(['C0FI']);
            default: return new Set();
        }
    }

